body.script:
// Rotating/typewriter text (reserve height so layout doesn't shift when empty)
(function(){
  const phrases = ['Play. Share. Win.', 'Cotton Candyyyy', '67', 'kirk'];
  let rp = 0, ci = 0, deleting = false;
  const el = document.getElementById('rotating');

  // Reserve vertical space to avoid layout shifts while the text is blank.
  if (el){
    const prev = el.textContent;
    // hide visually while measuring but keep layout reserved
    el.style.visibility = 'hidden';
    const longest = phrases.reduce((a,b)=> a.length >= b.length ? a : b, '');
    el.textContent = longest || '\u00A0';
    const h = el.getBoundingClientRect().height;
    el.style.minHeight = Math.ceil(h) + 'px';
    // restore previous content (or a non-breaking space)
    el.textContent = prev || '\u00A0';
    el.style.visibility = '';
  }

  function tick(){
    const cur = phrases[rp];
    el.textContent = cur.substring(0, ci);
    if (!deleting) ci++; else ci--;
    let delay = deleting ? 50 : 110;
    if (!deleting && ci > cur.length) { deleting = true; delay = 1400; }
    else if (deleting && ci <= 0) { deleting = false; rp = (rp + 1) % phrases.length; delay = 400; }
    setTimeout(tick, delay);
  }
  tick();
})();

// Live local time + date
function updateTime(){
  const now = new Date();
  const time = now.toLocaleTimeString();
  const date = now.toLocaleDateString(undefined,{weekday:'short',month:'short',day:'numeric',year:'numeric'});
  const tEl = document.getElementById('time');
  const dEl = document.getElementById('date');
  if (tEl) tEl.textContent = time;
  if (dEl) dEl.textContent = date;
}
updateTime();
setInterval(updateTime, 1000);

// Battery percentage (iPhone-style bar)
(function(){
  const batEl = document.getElementById('battery');
  const levelEl = document.getElementById('battery-level');
  const labelEl = document.getElementById('battery-label');
  if (!batEl || !levelEl || !labelEl) return;
  if (!navigator.getBattery) { labelEl.textContent = 'n/a'; batEl.classList.add('no-battery'); return; }
  navigator.getBattery().then(b => {
    function refresh(){
      const pct = Math.round(b.level * 100);
      levelEl.style.width = pct + '%';
      labelEl.textContent = pct + '%';
      batEl.classList.toggle('charging', !!b.charging);
      batEl.classList.toggle('low', pct <= 15 && !b.charging);
    }
    refresh();
    b.addEventListener('levelchange', refresh);
    b.addEventListener('chargingchange', refresh);
  }).catch(()=>{ labelEl.textContent = 'n/a'; });
})();

// Battery percentage (iPhone-style bar)
(function(){
  const app = document.getElementById('app');
    const center = document.getElementById('center') || app;
    function fit(){
      try{
        const rect = center.getBoundingClientRect();
        const cw = Math.max(rect.width, center.offsetWidth || 0);
        const ch = Math.max(rect.height, center.offsetHeight || 0);
        const vw = window.innerWidth;
        const vh = window.innerHeight;
        const scale = Math.min(vw / cw, vh / ch, 1);
        app.style.transform = `scale(${scale})`;
        // center vertically when scaled
        const topGap = Math.max((vh - ch * scale) / 2, 0);
        app.style.paddingTop = topGap + 'px';
      }catch(e){/* ignore */}
    }
  window.addEventListener('resize', fit);
  window.addEventListener('load', fit);
  setTimeout(fit, 80);
})();

// Flowing gradient waves background (fade near cursor)
(function(){
  const canvas = document.getElementById('bg-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  let dpr = Math.max(1, window.devicePixelRatio || 1);
  let W = window.innerWidth, H = window.innerHeight;
  function resize(){
    dpr = Math.max(1, window.devicePixelRatio || 1);
    W = window.innerWidth; H = window.innerHeight;
    canvas.width = Math.floor(W * dpr);
    canvas.height = Math.floor(H * dpr);
    canvas.style.width = W + 'px';
    canvas.style.height = H + 'px';
    ctx.setTransform(dpr,0,0,dpr,0,0);
  }

  const rootStyle = getComputedStyle(document.documentElement);
  const c1 = (rootStyle.getPropertyValue('--cotton-one') || '#6699ff').trim();
  const c2 = (rootStyle.getPropertyValue('--cotton-two') || '#ff7ab8').trim();

  function hexToRgba(hex, a){
    hex = (hex+'').replace('#','').trim();
    if (hex.length === 3) hex = hex.split('').map(h=>h+h).join('');
    const v = parseInt(hex,16);
    const r = (v>>16)&255, g=(v>>8)&255, b=v&255;
    return `rgba(${r},${g},${b},${a})`;
  }

  let mouse = { x:-9999, y:-9999, active:false };
  window.addEventListener('mousemove', (e)=>{ mouse.x = e.clientX; mouse.y = e.clientY; mouse.active = true; });
  window.addEventListener('mouseleave', ()=>{ mouse.active = false; });
  window.addEventListener('touchmove', (e)=>{ if (e.touches && e.touches[0]) { mouse.x = e.touches[0].clientX; mouse.y = e.touches[0].clientY; mouse.active = true; } }, { passive: true });
  window.addEventListener('touchend', ()=>{ mouse.active = false; });

  let layers = [];
  function buildLayers(){
    const base = Math.max(24, H * 0.05);
    layers = [
      { amp: base * 1.1, freq: 0.008, speed: 0.0010, offset: H * 0.46, alpha: 0.16 },
      { amp: base * 1.8, freq: 0.0055, speed: 0.0007, offset: H * 0.58, alpha: 0.12 },
      { amp: base * 2.8, freq: 0.0035, speed: 0.00045, offset: H * 0.70, alpha: 0.09 }
    ];
  }

  // visual effects: lightning bolts + water splashes
  let bolts = [];
  let splashes = [];
  // limits to avoid visual buildup / whiteout (increased to allow large logo bursts)
  const MAX_BOLTS = 24;
  const MAX_SPLASHES = 30;
  // tuned rates (slightly increased global spawn rate; logo hits still spawn many bolts)
  const lightningRate = 0.50; // avg bolts per second (slightly higher)
  const splashRate = 0.8; // avg splashes per second
  let lastFrame = performance.now();

  function spawnLightning(now){
    if (bolts.length >= MAX_BOLTS) return; // avoid too many at once
    const startX = Math.random() * W;
    const startY = Math.random() * Math.max(40, H * 0.12);
    const segs = 4 + Math.floor(Math.random() * 5);
    const path = [startX, startY];
    let x = startX;
    for (let i=0;i= MAX_SPLASHES) splashes.shift();
    splashes.push(s);
  }

  // helper to create jagged bolt path from start -> target
  function createBoltPath(sx, sy, tx, ty, segs){
    const path = [sx, sy];
    for (let i=1;i<=segs;i++){
      const t = i / segs;
      const nx = sx + (tx - sx) * t + (Math.random() - 0.5) * (120 * (1 - t));
      const ny = sy + (ty - sy) * t + (Math.random() * (H * 0.02 + 8));
      path.push(nx, ny);
    }
    path.push(tx, ty);
    return path;
  }

  // Spawn multiple bolts from the logo center outward across the screen
  function spawnLogoBolts(now, logoRect){
    try{
      const cx = logoRect.left + logoRect.width / 2;
      const cy = logoRect.top + logoRect.height / 2;
      const count = 15; // spawn ~15 bolts when logo is hit
      const available = Math.max(0, MAX_BOLTS - bolts.length);
      const spawnCount = Math.min(count, available);
      for (let i=0;i H * 0.55) {
          const s = { x: tx, y: ty, birth: now - 40, ttl: 400 + Math.random() * 600, maxR: 12 + Math.random() * 30 };
          if (splashes.length >= MAX_SPLASHES) splashes.shift();
          splashes.push(s);
        }
      }
    }catch(e){/* ignore */}
  }

  // geometry helpers: segment-rectangle and segment-segment intersection
  function pointInRect(x,y,rect){
    return x >= rect.left && x <= rect.right && y >= rect.top && y <= rect.bottom;
  }
  function onSegment(ax,ay,bx,by,cx,cy){
    return Math.min(ax,bx) <= cx && cx <= Math.max(ax,bx) && Math.min(ay,by) <= cy && cy <= Math.max(ay,by);
  }
  function orient(ax,ay,bx,by,cx,cy){
    return (bx-ax)*(cy-ay) - (by-ay)*(cx-ax);
  }
  function segmentsIntersect(a1x,a1y,a2x,a2y,b1x,b1y,b2x,b2y){
    const o1 = orient(a1x,a1y,a2x,a2y,b1x,b1y);
    const o2 = orient(a1x,a1y,a2x,a2y,b2x,b2y);
    const o3 = orient(b1x,b1y,b2x,b2y,a1x,a1y);
    const o4 = orient(b1x,b1y,b2x,b2y,a2x,a2y);
    if (o1 === 0 && onSegment(a1x,a1y,a2x,a2y,b1x,b1y)) return true;
    if (o2 === 0 && onSegment(a1x,a1y,a2x,a2y,b2x,b2y)) return true;
    if (o3 === 0 && onSegment(b1x,b1y,b2x,b2y,a1x,a1y)) return true;
    if (o4 === 0 && onSegment(b1x,b1y,b2x,b2y,a2x,a2y)) return true;
    return (o1 > 0) !== (o2 > 0) && (o3 > 0) !== (o4 > 0);
  }
  function segmentIntersectsRect(x1,y1,x2,y2,rect){
    if (pointInRect(x1,y1,rect) || pointInRect(x2,y2,rect)) return true;
    // rect edges
    const l = rect.left, r = rect.right, t = rect.top, b = rect.bottom;
    if (segmentsIntersect(x1,y1,x2,y2, l,t, r,t)) return true;
    if (segmentsIntersect(x1,y1,x2,y2, r,t, r,b)) return true;
    if (segmentsIntersect(x1,y1,x2,y2, r,b, l,b)) return true;
    if (segmentsIntersect(x1,y1,x2,y2, l,b, l,t)) return true;
    return false;
  }

  let t0 = performance.now();
  function draw(now){
    const dt = Math.max(0, (now - lastFrame) / 1000);
    lastFrame = now;
    const t = (now - t0);
    ctx.clearRect(0,0,W,H);

    ctx.globalCompositeOperation = 'source-over';
    // draw layered sine waves
    for (let i=0;i<layers.length;i++){
      const l = layers[i];
      const step = Math.max(12, Math.round(W / 120));
      ctx.beginPath();
      ctx.moveTo(0, H);
      for (let x=0;x<=W;x+=step){
        const y = l.offset + Math.sin((x * l.freq) + t * l.speed + i * 1.6) * l.amp;
        ctx.lineTo(x, y);
      }
      ctx.lineTo(W, H);
      ctx.closePath();

      const grad = ctx.createLinearGradient(0, l.offset - l.amp*1.2, 0, l.offset + l.amp*1.2);
      grad.addColorStop(0, hexToRgba(c1, l.alpha));
      grad.addColorStop(1, hexToRgba(c2, 0));
      ctx.fillStyle = grad;
      ctx.fill();
    }

    // spawn effects probabilistically based on dt
    if (Math.random() < lightningRate * dt) spawnLightning(now);
    if (Math.random() < splashRate * dt) spawnSplash(now);

    // draw splashes (below bolts)
    for (let i = splashes.length - 1; i >= 0; i--){
      const s = splashes[i];
      const age = now - s.birth;
      if (age > s.ttl){ splashes.splice(i,1); continue; }
      const life = age / s.ttl;
      const r = s.maxR * (0.6 + life * 1.8);
      const a = 1 - life;
      // soft radial splat
      const g = ctx.createRadialGradient(s.x, s.y, 0, s.x, s.y, r);
      g.addColorStop(0, hexToRgba(c2, 0.32 * a));
      g.addColorStop(0.3, hexToRgba(c1, 0.22 * a));
      g.addColorStop(1, 'rgba(255,255,255,0)');
      ctx.globalCompositeOperation = 'lighter';
      ctx.fillStyle = g;
      ctx.beginPath(); ctx.arc(s.x, s.y, r, 0, Math.PI*2); ctx.fill();
      // ripple ring
      ctx.lineWidth = 1 + (1 - a) * 2;
      ctx.strokeStyle = hexToRgba(c2, 0.18 * a);
      ctx.beginPath(); ctx.arc(s.x, s.y, r * 1.05, 0, Math.PI*2); ctx.stroke();
      ctx.globalCompositeOperation = 'source-over';
    }

    // draw lightning bolts on top (larger, top->water)
    for (let i = bolts.length - 1; i >= 0; i--){
      const b = bolts[i];
      // compute / register impact coordinates once
      if (b && !b._impactSet){
        const li = b.path.length - 2;
        b.impactX = (b.impactX !== undefined) ? b.impactX : (b.path[li] || 0);
        b.impactY = (b.impactY !== undefined) ? b.impactY : (b.path[li+1] || 0);
        b._impactSet = true;
      }
      // if this bolt landed on the logo, spawn many bolts from the logo
      try{
        const logoEl = document.getElementById('logo');
        if (logoEl && b && !b._logoTriggered && b.path && b.path.length >= 4){
          const rect = logoEl.getBoundingClientRect();
          let hit = false;
          for (let s=0; s < b.path.length - 2; s += 2){
            const x1 = b.path[s], y1 = b.path[s+1], x2 = b.path[s+2], y2 = b.path[s+3];
            if (segmentIntersectsRect(x1,y1,x2,y2, rect)) { hit = true; break; }
          }
          if (hit){ b._logoTriggered = true; spawnLogoBolts(now, rect); }
        }
      }catch(e){/* ignore */}
      const age = now - b.birth;
      if (age > b.ttl){ bolts.splice(i,1); continue; }
      const life = age / b.ttl;
      const alpha = Math.pow(1 - life, 4);
      const ys = [];
      for (let k=1;k<b.path.length;k+=2) ys.push(b.path[k]);
      const minY = Math.min(...ys), maxY = Math.max(...ys);
      const grad = ctx.createLinearGradient(0, minY, 0, maxY);
      grad.addColorStop(0, hexToRgba(c1, 0.95 * alpha));
      grad.addColorStop(0.5, `rgba(255,255,255,${0.95 * alpha})`);
      grad.addColorStop(1, hexToRgba(c2, 0.95 * alpha));

      ctx.save();
      ctx.globalCompositeOperation = 'lighter';
      ctx.lineJoin = 'round'; ctx.lineCap = 'round';
      ctx.lineWidth = 7 * (1 + (1 - life) * 0.5); // toned down stroke
      ctx.strokeStyle = grad;
      ctx.shadowBlur = 18 * alpha; ctx.shadowColor = hexToRgba(c2, 0.7 * alpha);
      ctx.beginPath(); ctx.moveTo(b.path[0], b.path[1]);
      for (let p = 2; p < b.path.length; p += 2) ctx.lineTo(b.path[p], b.path[p+1]);
      ctx.stroke();
      // bright core
      ctx.lineWidth = 2;
      ctx.shadowBlur = 6 * alpha; ctx.shadowColor = 'rgba(255,255,255,0.85)';
      ctx.strokeStyle = `rgba(255,255,255,${0.9 * alpha})`;
      ctx.beginPath(); ctx.moveTo(b.path[0], b.path[1]);
      for (let p = 2; p < b.path.length; p += 2) ctx.lineTo(b.path[p], b.path[p+1]);
      ctx.stroke();
      ctx.restore();

      // larger impact flash near water when the bolt is young
      if (life < 0.25){
        const mx = b.impactX || b.path[b.path.length-2];
        const my = b.impactY || b.path[b.path.length-1];
        const fr = 18 + Math.random()*48;
        const fg = ctx.createRadialGradient(mx, my, 0, mx, my, fr);
        fg.addColorStop(0, `rgba(255,255,255,${0.28 * (1-life)})`);
        fg.addColorStop(0.3, hexToRgba(c2, 0.28 * (1-life)));
        fg.addColorStop(1, 'rgba(255,255,255,0)');
        ctx.globalCompositeOperation = 'lighter';
        ctx.fillStyle = fg; ctx.beginPath(); ctx.arc(mx, my, fr, 0, Math.PI*2); ctx.fill();
        ctx.globalCompositeOperation = 'source-over';
      }
    }

    requestAnimationFrame(draw);
  }

  window.addEventListener('resize', ()=>{ resize(); buildLayers(); });
  resize(); buildLayers(); requestAnimationFrame(draw);
})();

    (function(){
      const taskbar = document.getElementById('taskbar');
      if (!taskbar) return;
      let visible = false;
      let hideTimer = 0;
      const SHOW_THRESHOLD = 48; // px from bottom
      // if taskbar starts hidden, mark it inert where supported
      try { if (taskbar.getAttribute('aria-hidden') === 'true') taskbar.setAttribute('inert', ''); } catch(e){}
      function showTaskbar(){
        if (!visible){
          try { taskbar.removeAttribute('inert'); } catch(e){}
          taskbar.classList.add('visible');
          taskbar.setAttribute('aria-hidden','false');
          visible = true;
        }
        clearTimeout(hideTimer);
        hideTimer = setTimeout(hideTaskbar, 3500);
      }
      function hideTaskbar(){
        if (visible){
          // if a focused element lives inside the taskbar, move focus first
          try{
            const active = document.activeElement;
            if (active && taskbar.contains(active)){
              try { active.blur(); } catch(err){}
              const app = document.getElementById('app') || document.body;
              if (app && typeof app.focus === 'function'){
                if (!app.hasAttribute('tabindex')) app.setAttribute('tabindex','-1');
                try { app.focus({preventScroll:true}); } catch(e){ app.focus(); }
              }
            }
          }catch(e){}

          taskbar.classList.remove('visible');
          taskbar.setAttribute('aria-hidden','true');
          try { taskbar.setAttribute('inert',''); } catch(e){}
          visible = false;
        }
        clearTimeout(hideTimer);
      }
      window.addEventListener('mousemove', (e)=>{
        try{
          if (window.innerHeight - e.clientY <= SHOW_THRESHOLD) showTaskbar();
          else { clearTimeout(hideTimer); hideTimer = setTimeout(hideTaskbar, 900); }
        }catch(err){}
      });
      window.addEventListener('touchstart', (e)=>{
        if (e.touches && e.touches[0] && window.innerHeight - e.touches[0].clientY <= SHOW_THRESHOLD) showTaskbar();
      }, {passive:true});
      window.addEventListener('mouseleave', hideTaskbar);
        window.addEventListener('scroll', ()=>{
          const nearBottom = (window.innerHeight + window.scrollY) >= (document.body.offsetHeight - SHOW_THRESHOLD);
          if (nearBottom) showTaskbar(); else hideTaskbar();
        }, {passive:true});

        // Dock magnification effect (mousemove-based) for Mac-like behavior
        (function(){
          const dock = document.querySelector('#taskbar .bar.dock');
          if (!dock) return;
          const items = Array.from(dock.querySelectorAll('.task-btn'));
          const maxDistance = 140; // px where effect falls off
          const maxScale = 1.9;

          function resetItems(){
            items.forEach(it => { it.style.transform = ''; it.style.zIndex = ''; });
          }

          dock.addEventListener('mousemove', (ev) => {
            const x = ev.clientX;
            items.forEach(it => {
              const r = it.getBoundingClientRect();
              const cx = r.left + r.width/2;
              const dist = Math.abs(cx - x);
              const ratio = Math.max(0, 1 - dist / maxDistance);
              const scale = 1 + ratio * (maxScale - 1);
              const ty = -Math.round(ratio * 14);
              it.style.transform = `translateY(${ty}px) scale(${scale})`;
              it.style.zIndex = Math.round(1000 * ratio) + 1;
            });
          });

          dock.addEventListener('mouseleave', resetItems);
          dock.addEventListener('touchstart', resetItems, {passive:true});
        })();

        // chatroom modal helpers (load remote chat like `customizable.html`)
        const CHATROOM_URL = 'https://cdn.jsdelivr.net/gh/Zaapiz/zaapizsgamecorner@main/customhtmls/chatroom.html';
        const chatModal = document.getElementById('chatroom-modal');
        const chatContainer = document.getElementById('chatroom-container');
        const chatClose = document.getElementById('chatroom-close');

        async function loadChatroom() {
          const container = chatContainer || (chatModal && chatModal.querySelector('#chatroom-container'));
          if (!container) return;
          // avoid reloading if already loaded
          if (container.querySelector('iframe')) return;
          try {
            const res = await fetch(CHATROOM_URL);
            const html = await res.text();
            const iframe = document.createElement('iframe');
            iframe.id = 'chatroom-iframe';
            iframe.style.width = '100%';
            iframe.style.height = '100%';
            iframe.style.border = '0';
            iframe.style.display = 'block';
            iframe.setAttribute('allow', 'microphone; camera; autoplay; clipboard-write; encrypted-media; fullscreen; geolocation');
            iframe.setAttribute('allowfullscreen', '');
            try {
              const baseUrl = new URL(CHATROOM_URL);
              const baseHref = baseUrl.origin + baseUrl.pathname.substring(0, baseUrl.pathname.lastIndexOf('/') + 1);
              iframe.srcdoc = `` + html;
            } catch (e) {
              iframe.srcdoc = html;
            }
            container.innerHTML = '';
            container.appendChild(iframe);
          } catch (err) {
            container.innerHTML = '
Failed to load chatroom.';
            console.error('Chatroom load error:', err);
          }
        }

        function openChat(){
          if (chatModal){
            chatModal.classList.add('visible');
            chatModal.setAttribute('aria-hidden','false');
            loadChatroom().catch(()=>{});
          }
        }

        function closeChat(){
          if (chatModal){
            chatModal.classList.remove('visible');
            chatModal.setAttribute('aria-hidden','true');
          }
        }

        // proxy modal helpers (loads inline proxy template into an iframe)
        const proxyModal = document.getElementById('proxy-modal');
        const proxyContainer = document.getElementById('proxy-container');
        const proxyClose = document.getElementById('proxy-close');

        // cloudmoon modal helpers (load remote Cloudmoon page)
        const CLOUDMOON_URL = 'https://cdn.jsdelivr.net/gh/Zaapiz/zaapizchat2@main/index.html';
        const cloudModal = document.getElementById('cloudmoon-modal');
        const cloudContainer = document.getElementById('cloudmoon-container');
        const cloudClose = document.getElementById('cloudmoon-close');

        async function loadCloudmoon() {
          const container = cloudContainer || (cloudModal && cloudModal.querySelector('#cloudmoon-container'));
          if (!container) return;
          if (container.querySelector('iframe')) return;
          try {
            const res = await fetch(CLOUDMOON_URL);
            const html = await res.text();
            const iframe = document.createElement('iframe');
            iframe.id = 'cloudmoon-iframe';
            iframe.style.width = '100%';
            iframe.style.height = '100%';
            iframe.style.border = '0';
            iframe.style.display = 'block';
            iframe.setAttribute('allow', 'microphone; camera; autoplay; clipboard-write; encrypted-media; fullscreen; geolocation');
            iframe.setAttribute('allowfullscreen', '');
            try {
              const baseUrl = new URL(CLOUDMOON_URL);
              const baseHref = baseUrl.origin + baseUrl.pathname.substring(0, baseUrl.pathname.lastIndexOf('/') + 1);
              iframe.srcdoc = `` + html;
            } catch (e) {
              iframe.srcdoc = html;
            }
            container.innerHTML = '';
            container.appendChild(iframe);
          } catch (err) {
            container.innerHTML = '
Failed to load Cloudmoon.';
            console.error('Cloudmoon load error:', err);
          }
        }

        function openCloudmoon(){
          if (cloudModal) {
            cloudModal.classList.add('visible');
            cloudModal.setAttribute('aria-hidden','false');
            loadCloudmoon().catch(()=>{});
          }
        }

        function closeCloudmoon(){
          if (cloudModal){
            cloudModal.classList.remove('visible');
            cloudModal.setAttribute('aria-hidden','true');
          }
        }

        // games modal helpers (load remote games page)
        const GAMES_URL = 'https://cdn.jsdelivr.net/gh/Zaapiz/zaapizsgamecorner@main/customhtmls/games.html';
        const gamesModal = document.getElementById('games-modal');
        const gamesContainer = document.getElementById('games-container');
        const gamesClose = document.getElementById('games-close');

        async function loadGames() {
          const container = gamesContainer || (gamesModal && gamesModal.querySelector('#games-container'));
          if (!container) return;
          if (container.querySelector('iframe')) return;
          try {
            const res = await fetch(GAMES_URL);
            const html = await res.text();
            const iframe = document.createElement('iframe');
            iframe.id = 'games-iframe';
            iframe.style.width = '100%';
            iframe.style.height = '100%';
            iframe.style.border = '0';
            iframe.style.display = 'block';
            iframe.setAttribute('allow', 'microphone; camera; autoplay; clipboard-write; encrypted-media; fullscreen; geolocation');
