    let ntWordIdx = 0, ntCharIdx = 0, ntIsDeleting = false;
    function ntType() {
      const target = document.getElementById("typewriter");
      if (!target) return;
      const currentWord = ntWords[ntWordIdx];
      target.textContent = currentWord.substring(0, ntCharIdx);
      if (ntIsDeleting) ntCharIdx--; else ntCharIdx++;
      let typeSpeed = ntIsDeleting ? 50 : 120;
      if (!ntIsDeleting && ntCharIdx > currentWord.length) { ntIsDeleting = true; typeSpeed = 2000; }
      else if (ntIsDeleting && ntCharIdx < 0) { ntIsDeleting = false; ntWordIdx = (ntWordIdx + 1) % ntWords.length; ntCharIdx = 0; typeSpeed = 500; }
      setTimeout(ntType, typeSpeed);
