          const applyCustom = document.getElementById('applyCustomCloak'); if(applyCustom) applyCustom.addEventListener('click', applyCustomCloak);
          const setPk = document.getElementById('setPanicKeyBtn'); if(setPk) setPk.addEventListener('click', setPanicKey);
          const preview = document.getElementById('previewPanicBtn'); if(preview) preview.addEventListener('click', panicOn);
          const hide = document.getElementById('hidePanicBtn'); if(hide) hide.addEventListener('click', panicOff);
        }

        // ensure global access for quick testing
        window.panicOn = panicOn;
        window.panicOff = panicOff;
      })();



        // Disable/remove the Customize modal and Panic overlay to avoid showing inside the proxy view.
        (function(){
          function disableCustomize(){
            try{
              const modal = document.getElementById('customizeModal');
              if(modal) modal.remove();
              const panic = document.getElementById('panicScreen');
              if(panic) panic.remove();

              // Override global functions that open or render the customize UI so they become no-ops
              try{ window.openCustomize = function(){}; }catch(e){}
              try{ window.closeCustomize = function(){}; }catch(e){}
              try{ window.renderCustomize = function(){}; }catch(e){}
              try{ window.applyCloak = function(){}; }catch(e){}
              try{ window.applyCustomCloak = function(){}; }catch(e){}
              try{ window.removeCloak = function(){}; }catch(e){}
              try{ window.setPanicKey = function(){}; }catch(e){}
              try{ window.panicOn = function(){}; }catch(e){}
              try{ window.panicOff = function(){}; }catch(e){}
            }catch(err){ console.warn('disableCustomize error', err); }
          }
          if (document.readyState === 'complete' || document.readyState === 'interactive') disableCustomize();
          else document.addEventListener('DOMContentLoaded', disableCustomize);
        })();
